import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Authentication — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Authentication — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/authentication"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Authentication — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/authentication"}]]},"headers":[],"relativePath":"user-guide/authentication.md","filePath":"user-guide/authentication.md","lastUpdated":1784655479000}'),n={name:"user-guide/authentication.md"};function i(s,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="authentication-—-user-guide" tabindex="-1">Authentication — User Guide <a class="header-anchor" href="#authentication-—-user-guide" aria-label="Permalink to &quot;Authentication — User Guide&quot;">​</a></h1><h2 id="tenant-application" tabindex="-1">Tenant Application <a class="header-anchor" href="#tenant-application" aria-label="Permalink to &quot;Tenant Application&quot;">​</a></h2><h3 id="register" tabindex="-1">Register <a class="header-anchor" href="#register" aria-label="Permalink to &quot;Register&quot;">​</a></h3><ol><li>Open <code>/register</code>.</li><li>If registration is closed, you will see: <strong>We are not currently accepting new registrations.</strong></li><li>Otherwise enter company name, your name, work email, password, and optional workspace domain.</li><li>After success you are signed in and taken to the workspace dashboard.</li></ol><p>Registration creates your workspace, owner account, default roles, and default modules (Leads, Tasks, Communication Templates).</p><h3 id="login" tabindex="-1">Login <a class="header-anchor" href="#login" aria-label="Permalink to &quot;Login&quot;">​</a></h3><ol><li>Open <code>/login</code>.</li><li>Enter your workspace, email, and password. The workspace is preselected when you open the application on its workspace domain.</li><li>Optionally enable <strong>Remember me</strong>.</li><li>Verify your email when prompted; unverified accounts cannot open protected workspace pages. On the verify-email gate, <strong>Sign out</strong> ends the session and returns you to <code>/login</code> (or <code>/central/login</code> for Central).</li><li>After success you land on <code>/dashboard</code>.</li></ol><p>If a new member never receives the verification email, a workspace owner or admin can open <strong>Administration → Users</strong>, open that user’s row menu, and either <strong>Resend verification</strong> or <strong>Mark as verified</strong>.</p><p>Your browser does not save a workspace selection in local storage. Open the correct workspace host or enter the workspace again when using the shared login URL.</p><h3 id="forgot-password" tabindex="-1">Forgot password <a class="header-anchor" href="#forgot-password" aria-label="Permalink to &quot;Forgot password&quot;">​</a></h3><ol><li>Open <code>/forgot-password</code> (or use the link on the login page).</li><li>Enter your email and submit.</li><li>If an account exists, you receive a reset email.</li></ol><h3 id="reset-password" tabindex="-1">Reset password <a class="header-anchor" href="#reset-password" aria-label="Permalink to &quot;Reset password&quot;">​</a></h3><ol><li>Open the link from your email (<code>/reset-password/{token}?email=…</code>).</li><li>Enter and confirm a new password that meets platform password rules.</li><li>After success you are redirected to <code>/login</code>.</li></ol><h3 id="logout" tabindex="-1">Logout <a class="header-anchor" href="#logout" aria-label="Permalink to &quot;Logout&quot;">​</a></h3><p>Use <strong>Sign out</strong> on the tenant dashboard. Your session token is revoked.</p><hr><h2 id="central-application-platform-admins" tabindex="-1">Central Application (platform admins) <a class="header-anchor" href="#central-application-platform-admins" aria-label="Permalink to &quot;Central Application (platform admins)&quot;">​</a></h2><p>Central auth lives under <code>/central/*</code>.</p><table tabindex="0"><thead><tr><th>Action</th><th>URL</th></tr></thead><tbody><tr><td>Login</td><td><code>/central/login</code></td></tr><tr><td>Forgot password</td><td><code>/central/forgot-password</code></td></tr><tr><td>Reset password</td><td><code>/central/reset-password/{token}?email=</code></td></tr><tr><td>Admin console</td><td><code>/central/dashboard</code></td></tr></tbody></table><p>Central users are invited by administrators; there is no public Central registration page.</p><p>Central administrators must also verify their invited email address before accessing protected Central pages.</p>',21)])])}const m=t(n,[["render",i]]);export{h as __pageData,m as default};
